36: /**
37:  * A trade in a single-name credit default swap (CDS).
38:  * <p>
39:  * An Over-The-Counter (OTC) trade in a {@link Cds}.
40:  * <p>
41:  * A CDS is a financial instrument where the protection seller agrees to compensate
42:  * the protection buyer when the reference entity suffers a default.
43:  * The protection seller is paid premium regularly from the protection buyer until
44:  * the expiry of the CDS contract or the reference entity defaults before the expiry.
45:  */
46: @BeanDefinition
47: public final class CdsTrade
48:     implements ProductTrade, ResolvableTrade<ResolvedCdsTrade>, ImmutableBean, Serializable {
49: 
50:   /**
51:    * The additional trade information, defaulted to an empty instance.
52:    * <p>
53:    * This allows additional information to be attached to the trade.
54:    */
55:   @PropertyDefinition(validate = "notNull", overrideGet = true)
56:   private final TradeInfo info;
57:   /**
58:    * The CDS product that was agreed when the trade occurred.
59:    * <p>
60:    * The product captures the contracted financial details of the trade.
61:    */
62:   @PropertyDefinition(validate = "notNull", overrideGet = true)
63:   private final Cds product;
64:   /**
65:    * The upfront fee of the product.
66:    * <p>
67:    * This specifies a single amount payable by the buyer to the seller.
68:    * Thus the sign must be compatible with the product Pay/Receive flag.
69:    * <p>
70:    * Some CDSs, especially legacy products, are traded at par and the upfront fee is not paid.
71:    */
72:   @PropertyDefinition(get = "optional")
73:   private final AdjustablePayment upfrontFee;
74: 
75:   //-------------------------------------------------------------------------
76:   @Override
77:   public CdsTrade withInfo(PortfolioItemInfo info) {
78:     return new CdsTrade(TradeInfo.from(info), product, upfrontFee);
79:   }
80: 
81:   //-------------------------------------------------------------------------
82:   @Override
83:   public PortfolioItemSummary summarize() {
84:     // 2Y Buy USD 1mm ENTITY / 1.5% : 21Jan18-21Jan20
85:     PeriodicSchedule paymentSchedule = product.getPaymentSchedule();
86:     StringBuilder buf = new StringBuilder(96);
87:     buf.append(SummarizerUtils.datePeriod(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
88:     buf.append(' ');
89:     buf.append(product.getBuySell());
90:     buf.append(' ');
91:     buf.append(SummarizerUtils.amount(product.getCurrency(), product.getNotional()));
92:     buf.append(' ');
93:     buf.append(product.getLegalEntityId().getValue());
94:     buf.append(" / ");
95:     buf.append(SummarizerUtils.percent(product.getFixedRate()));
96:     buf.append(" : ");
97:     buf.append(SummarizerUtils.dateRange(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
98:     return SummarizerUtils.summary(this, ProductType.CDS, buf.toString(), product.getCurrency());
99:   }
