    if (calculator == null) {
      return Result.failure(FailureReason.UNSUPPORTED, "Unsupported measure for CdsTrancheTrade: {}", measure);
    }
    return Result.of(() -> calculator.calculate(trade, marketData, refData));
  }

  //-------------------------------------------------------------------------
  // calculation methods
  private static Object presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    // This would use the tranche pricer to calculate present value
    // For now, return a placeholder
    return com.opengamma.strata.basics.currency.CurrencyAmount.of(
        trade.getProduct().getUnderlyingIndex().getCurrency(), 0.0);
  }

  private static Object unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    // This would use the tranche pricer to calculate unit price
    // For now, return a placeholder
    return 0.0;
  }

  //-------------------------------------------------------------------------
  @FunctionalInterface
  interface SingleMeasureCalculation {
    public abstract Object calculate(
        ResolvedCdsTrancheTrade trade,
        CreditRatesScenarioMarketData marketData,
        ReferenceData refData);
  }

}

